{"command": "# 检查 PC-DMIS 是否安装
$paths = @(
    "C:\Program Files\Hexagon\PC-DMIS",
    "C:\Program Files (x86)\Hexagon\PC-DMIS",
    "C:\Program Files\HexagonMetrology\PC-DMIS",
    "C:\Program Files (x86)\HexagonMetrology\PC-DMIS"
)
foreach ($p in $paths) {
    if (Test-Path $p) {
        Write-Host "找到: $p"
        Get-ChildItem $p -Depth 0 -ErrorAction SilentlyContinue | Select-Object Name
    }
}

# 检查 pcdmis-mcp.exe 的运行情况
Write-Host "`n--- MCP 服务器信息 ---"
# 查看文件版本等信息
(Get-Item "D:\AI_LLM\LLM\claw-code\tools\pcdmis-mcp.exe").VersionInfo | Format-List *", "description": "检查 PC-DMIS 安装状态和 MCP 服务器信息"}

{"command": "# 检查 PCDLRN COM 对象是否注册
$com = Get-ItemProperty -Path "HKLM:\SOFTWARE\Classes\PCDLRN.Application" -ErrorAction SilentlyContinue
if ($com) {
    Write-Host "✅ PCDLRN.Application COM 已注册"
    $com | Format-List *
} else {
    Write-Host "❌ PCDLRN.Application COM 未注册（PC-DMIS 可能未安装）"
}

# 也检查一下 32-bit 注册表
$com32 = Get-ItemProperty -Path "HKLM:\SOFTWARE\WOW6432Node\Classes\PCDLRN.Application" -ErrorAction SilentlyContinue
if ($com32) {
    Write-Host "✅ PCDLRN.Application (32-bit) COM 已注册"
} else {
    Write-Host "ℹ️ PCDLRN.Application (32-bit) COM 未注册"
}

# 搜索 PC-DMIS 相关进程
$procs = Get-Process -Name "*pcd*", "*pc-dmis*", "*pc_dmis*" -ErrorAction SilentlyContinue
if ($procs) {
    Write-Host "`nPC-DMIS 进程:"
    $procs | Format-Table Name, Id
} else {
    Write-Host "`n❌ 没有运行中的 PC-DMIS 进程"
}", "description": "检查 PC-DMIS COM 注册和运行状态"}

